<script setup lang="ts">
import { computed, ref } from 'vue'
import { useMutation, useQuery, useQueryClient } from '@tanstack/vue-query'
import { KeyRound, Plus, RefreshCw, ShieldCheck, Trash2, UserRoundCog, UsersRound, X } from 'lucide-vue-next'
import Button from '@/components/ui/Button.vue'
import StatusBadge from '@/components/ui/StatusBadge.vue'
import { createAdminUser, createRole, deleteRole, disableAdminUser, getAdminUsers, getPermissions, getRoles, updateAdminUser, updateRole, type AdminUser, type Role } from '@/lib/api'

const client=useQueryClient();const tab=ref<'users'|'roles'|'permissions'>('users');const dialog=ref<'user'|'role'|null>(null);const editingUser=ref<AdminUser|null>(null);const editingRole=ref<Role|null>(null);const error=ref('')
const users=useQuery({queryKey:['admin-users'],queryFn:getAdminUsers});const roles=useQuery({queryKey:['admin-roles'],queryFn:getRoles});const permissions=useQuery({queryKey:['admin-permissions'],queryFn:getPermissions})
const userForm=ref({email:'',display_name:'',password:'',disabled:false,role_ids:[] as string[]});const roleForm=ref({slug:'',name:'',description:'',permission_ids:[] as string[]})
const invalidate=()=>Promise.all([client.invalidateQueries({queryKey:['admin-users']}),client.invalidateQueries({queryKey:['admin-roles']})])
const close=()=>{dialog.value=null;editingUser.value=null;editingRole.value=null;error.value=''}
const openUser=(user?:AdminUser)=>{editingUser.value=user??null;userForm.value=user?{email:user.email,display_name:user.display_name,password:'',disabled:!!user.disabled_at,role_ids:(roles.data.value??[]).filter(role=>user.roles.includes(role.slug)).map(role=>role.id)}:{email:'',display_name:'',password:'',disabled:false,role_ids:[]};dialog.value='user'}
const openRole=(role?:Role)=>{editingRole.value=role??null;roleForm.value=role?{slug:role.slug,name:role.name,description:role.description,permission_ids:(permissions.data.value??[]).filter(permission=>role.permissions.includes(permission.slug)).map(permission=>permission.id)}:{slug:'',name:'',description:'',permission_ids:[]};dialog.value='role'}
const saveUser=useMutation({mutationFn:()=>editingUser.value?updateAdminUser(editingUser.value.id,{email:userForm.value.email,display_name:userForm.value.display_name,disabled:userForm.value.disabled,role_ids:userForm.value.role_ids}):createAdminUser({email:userForm.value.email,display_name:userForm.value.display_name,password:userForm.value.password,role_ids:userForm.value.role_ids}),onSuccess:async()=>{await invalidate();close()},onError:(value:any)=>error.value=value?.response?.data?.error?.message??'Não foi possível salvar o usuário.'})
const saveRole=useMutation({mutationFn:()=>editingRole.value?updateRole(editingRole.value.id,{name:roleForm.value.name,description:roleForm.value.description,permission_ids:roleForm.value.permission_ids}):createRole(roleForm.value),onSuccess:async()=>{await invalidate();close()},onError:(value:any)=>error.value=value?.response?.data?.error?.message??'Não foi possível salvar o papel.'})
const disable=useMutation({mutationFn:disableAdminUser,onSuccess:invalidate});const removeRole=useMutation({mutationFn:deleteRole,onSuccess:invalidate,onError:(value:any)=>error.value=value?.response?.data?.error?.message??'Não foi possível excluir o papel.'})
const loading=computed(()=>users.isLoading.value||roles.isLoading.value||permissions.isLoading.value);const failed=computed(()=>users.isError.value||roles.isError.value||permissions.isError.value)
const refresh=()=>{users.refetch();roles.refetch();permissions.refetch()}
</script>

<template><div class="mx-auto max-w-[1680px] space-y-5"><header class="flex flex-col justify-between gap-4 md:flex-row md:items-end"><div><div class="flex items-center gap-2 font-mono text-[10px] uppercase tracking-widest text-signal"><ShieldCheck class="h-3.5 w-3.5"/>Controle de privilégio mínimo</div><h1 class="mt-3 text-3xl font-semibold tracking-tight">Identidade e acesso</h1><p class="mt-2 text-sm text-muted">Usuários, papéis e permissões com mudanças auditadas e sessões revogáveis.</p></div><Button variant="outline" @click="refresh"><RefreshCw class="h-4 w-4"/>Atualizar</Button></header>
<nav class="flex gap-1 rounded-xl border border-line bg-panel/50 p-1" aria-label="Seções administrativas"><button v-for="item in [{id:'users',label:'Usuários'},{id:'roles',label:'Papéis'},{id:'permissions',label:'Permissões'}]" :key="item.id" :class="['flex-1 cursor-pointer rounded-lg px-3 py-2 text-xs transition-colors',tab===item.id?'bg-signal/10 text-signal':'text-muted hover:text-white']" @click="tab=item.id as typeof tab">{{item.label}}</button></nav>
<div v-if="failed" class="rounded-xl border border-danger/20 bg-danger/5 p-4 text-sm text-danger">O serviço administrativo não respondeu. Confirme que a API desta ramificação está em execução e que sua conta possui o papel god-admin.</div><div v-else-if="loading" class="grid min-h-72 place-items-center rounded-xl border border-line bg-panel/50"><div class="h-8 w-8 animate-spin rounded-full border-2 border-line border-t-signal"/></div>
<section v-else-if="tab==='users'" class="overflow-hidden rounded-xl border border-line bg-panel/65"><header class="flex items-center justify-between border-b border-line p-5"><div class="flex items-center gap-3"><UsersRound class="h-4 w-4 text-signal"/><div><h2 class="text-sm font-medium">Contas da plataforma</h2><p class="text-[11px] text-muted">{{users.data.value?.length??0}} identidades registradas</p></div></div><Button @click="openUser()"><Plus class="h-4 w-4"/>Novo usuário</Button></header><div class="divide-y divide-line/70"><button v-for="user in users.data.value" :key="user.id" class="grid w-full cursor-pointer gap-3 px-5 py-4 text-left transition-colors hover:bg-white/[.02] md:grid-cols-[1.4fr_1fr_140px]" @click="openUser(user)"><div><div class="flex items-center gap-2"><p class="text-sm text-slate-200">{{user.display_name}}</p><StatusBadge :status="user.disabled_at?'critical':'healthy'" :label="user.disabled_at?'desativado':'ativo'"/></div><p class="mt-1 font-mono text-[10px] text-muted">{{user.email}}</p></div><div class="flex flex-wrap items-center gap-1.5"><span v-for="role in user.roles" :key="role" class="rounded border border-line px-2 py-1 font-mono text-[9px] text-slate-400">{{role}}</span><span v-if="!user.roles.length" class="text-xs text-warning">Sem papel</span></div><div class="self-center text-xs text-muted md:text-right">TOTP {{user.totp_enabled?'ativo':'pendente'}}</div></button><div v-if="!users.data.value?.length" class="p-12 text-center text-sm text-muted">Nenhum usuário encontrado.</div></div></section>
<section v-else-if="tab==='roles'" class="grid gap-4 lg:grid-cols-2"><article v-for="role in roles.data.value" :key="role.id" class="rounded-xl border border-line bg-panel/65 p-5"><div class="flex items-start gap-3"><div class="grid h-10 w-10 place-items-center rounded-xl border border-pulse/20 bg-pulse/[.06]"><KeyRound class="h-4 w-4 text-pulse"/></div><div class="min-w-0 flex-1"><div class="flex items-center gap-2"><h2 class="text-sm font-medium">{{role.name}}</h2><span class="font-mono text-[9px] text-muted">{{role.slug}}</span></div><p class="mt-1 text-xs leading-5 text-muted">{{role.description||'Sem descrição.'}}</p></div><button class="cursor-pointer p-2 text-muted hover:text-danger" :disabled="role.slug==='god-admin'||role.user_count>0" title="Excluir papel" @click="removeRole.mutate(role.id)"><Trash2 class="h-4 w-4"/></button></div><div class="mt-5 flex items-center justify-between border-t border-line pt-4"><p class="text-[11px] text-muted">{{role.permissions.length}} permissões · {{role.user_count}} usuários</p><Button variant="outline" @click="openRole(role)">Editar matriz</Button></div></article><button class="min-h-44 cursor-pointer rounded-xl border border-dashed border-line text-sm text-muted transition-colors hover:border-signal/40 hover:text-signal" @click="openRole()"><Plus class="mx-auto mb-2 h-5 w-5"/>Criar papel</button></section>
<section v-else class="overflow-hidden rounded-xl border border-line bg-panel/65"><header class="border-b border-line p-5"><h2 class="text-sm font-medium">Catálogo de permissões</h2><p class="mt-1 text-xs text-muted">Recursos e ações definidos no servidor. A atribuição é feita na matriz de cada papel.</p></header><div class="grid gap-px bg-line sm:grid-cols-2 xl:grid-cols-3"><article v-for="permission in permissions.data.value" :key="permission.id" class="bg-[#0b111d] p-5"><div class="flex items-center justify-between gap-2"><code class="text-xs text-slate-200">{{permission.slug}}</code><StatusBadge :status="permission.risk==='critical'?'critical':permission.risk==='dangerous'?'warning':'healthy'" :label="permission.risk"/></div><p class="mt-3 text-xs leading-5 text-muted">{{permission.description}}</p></article></div></section>
<div v-if="dialog" class="fixed inset-0 z-50 flex items-center justify-center bg-black/75 p-4 backdrop-blur-sm" @click.self="close"><form class="max-h-[90vh] w-full max-w-xl overflow-y-auto rounded-xl border border-line bg-[#0b111d] p-6 shadow-2xl" @submit.prevent="dialog==='user'?saveUser.mutate():saveRole.mutate()"><header class="flex items-start"><div><p class="font-mono text-[10px] uppercase tracking-widest text-signal">Alteração de governança</p><h2 class="mt-2 text-xl font-semibold">{{editingUser||editingRole?'Editar':'Criar'}} {{dialog==='user'?'usuário':'papel'}}</h2></div><button type="button" class="ml-auto cursor-pointer p-2 text-muted hover:text-white" @click="close"><X class="h-4 w-4"/></button></header><div v-if="dialog==='user'" class="mt-6 space-y-4"><label class="block text-xs">Nome<input v-model="userForm.display_name" required class="field" autocomplete="name"/></label><label class="block text-xs">E-mail<input v-model="userForm.email" required type="email" class="field" autocomplete="email"/></label><label v-if="!editingUser" class="block text-xs">Senha temporária<input v-model="userForm.password" required minlength="12" type="password" class="field" autocomplete="new-password"/><span class="mt-1 block text-[10px] text-muted">Mínimo de 12 caracteres; compartilhe por canal seguro.</span></label><fieldset><legend class="mb-2 text-xs">Papéis</legend><label v-for="role in roles.data.value" :key="role.id" class="mb-2 flex cursor-pointer items-start gap-3 rounded-lg border border-line p-3 text-xs"><input v-model="userForm.role_ids" :value="role.id" type="checkbox" class="mt-0.5 accent-emerald-400"/><span><strong class="font-medium text-slate-200">{{role.name}}</strong><span class="mt-1 block text-muted">{{role.description}}</span></span></label></fieldset><label v-if="editingUser" class="flex items-center gap-3 rounded-lg border border-danger/20 bg-danger/5 p-3 text-xs text-danger"><input v-model="userForm.disabled" type="checkbox"/>Desativar conta e revogar sessões ativas</label></div><div v-else class="mt-6 space-y-4"><label class="block text-xs">Nome<input v-model="roleForm.name" required class="field"/></label><label class="block text-xs">Slug<input v-model="roleForm.slug" required :disabled="!!editingRole" pattern="[a-z][a-z0-9-]{2,47}" class="field" placeholder="operador-plataforma"/></label><label class="block text-xs">Descrição<textarea v-model="roleForm.description" class="field min-h-20 py-3"/></label><fieldset><legend class="mb-2 text-xs">Permissões</legend><label v-for="permission in permissions.data.value" :key="permission.id" class="mb-2 flex cursor-pointer items-start gap-3 rounded-lg border border-line p-3 text-xs"><input v-model="roleForm.permission_ids" :value="permission.id" type="checkbox" class="mt-0.5 accent-emerald-400"/><span class="min-w-0 flex-1"><span class="flex items-center justify-between gap-2"><code class="text-slate-200">{{permission.slug}}</code><StatusBadge :status="permission.risk==='critical'?'critical':permission.risk==='dangerous'?'warning':'healthy'" :label="permission.risk"/></span><span class="mt-1 block text-muted">{{permission.description}}</span></span></label></fieldset></div><p v-if="error" class="mt-4 rounded-lg border border-danger/20 bg-danger/5 p-3 text-xs text-danger">{{error}}</p><div class="mt-6 flex justify-end gap-2"><Button type="button" variant="ghost" @click="close">Cancelar</Button><Button type="submit">Salvar com auditoria</Button></div></form></div></div></template>
